const draw: Variants = {
  hidden: { pathLength: 0, opacity: 0 },
  visible: (i: number) => {
    const delay = i * 0.035; // Faster acceleration - each path starts sooner
    return {
      pathLength: 1,
      opacity: 1,
      transition: {
        pathLength: {
          delay,
          type: "spring",
          duration: 0.3,
          bounce: 0,
          stiffness: 120,
          damping: 25,
        },
        opacity: { delay, duration: 0.01 },
      },
    };
  },
  exit: (i: number) => {
    const totalPaths = 25; // Approximate max paths across all SVGs
    const reverseDelay = (totalPaths - i) * 0.015; // Reverse order, like erasing - faster
    return {
      pathLength: 0,
      opacity: 0,
      transition: {
        pathLength: {
          delay: reverseDelay,
          type: "spring",
          duration: 0.2,
          bounce: 0,
          stiffness: 300,
          damping: 30,
        },
        opacity: { delay: reverseDelay + 0.1, duration: 0.05 },
      },
    };
  },
};

const containerVariants: Variants = {
  hidden: { clipPath: "inset(0% 0% 0% 0%)" },
  visible: { clipPath: "inset(0% 0% 0% 0%)" },
};

interface HandwritingMVPProps {
  currentSvgIndex: number;
}

const HandwritingMVP: React.FC<HandwritingMVPProps> = ({ currentSvgIndex }) => {
  let currentPaths;
  let centerOffset = 0; // Offset to center content (viewBox center is 578)

  switch (currentSvgIndex) {
    case 0:
      currentPaths = MVP_PATHS;
      // MVP paths: min ~7.5, max ~1146, center ~576.75, viewBox center 578
      centerOffset = 578 - 576.75; // ~1.25
      break;
    case 1:
      currentPaths = MOBILE_APPS_PATHS;
      // Mobile Apps paths: min ~7.5, max ~758.5 (last path goes to ~758.489), center ~383, viewBox center 578
      centerOffset = 578 - 383; // ~195
      break;
    case 2:
      currentPaths = WEBAPP_PATHS;
      // Web App paths: min ~7.5, max ~1074, center ~540.75, viewBox center 578
      centerOffset = 578 - 540.75; // ~37.25
      break;
    case 3:
      currentPaths = SAAS_PATHS;
      // SAAS paths: min ~7.5, max ~1020, center ~513.75, viewBox center 578
      centerOffset = 578 - 513.75; // ~64.25
      break;
    case 4:
      currentPaths = N8N_PATHS;
      // N8N paths: min ~7.5, max ~1091, center ~549.25, viewBox center 578
      centerOffset = 578 - 549.25; // ~28.75
      break;
    case 5:
      currentPaths = AIINTE_PATHS;
      // AI paths: min ~7.5, max ~1039, center ~523.25, viewBox center 578
      centerOffset = 578 - 523.25; // ~54.75
      break;
    default:
      currentPaths = MVP_PATHS;
      centerOffset = 578 - 576.75; // ~1.25
  }

  const viewBox = "0 0 1156 165"; // Increased height to accommodate Mobile Apps (163px)
  const width = "1156";
  const height = "165";

  return (
    <div className="w-full flex items-center justify-center mt-2 min-h-[6rem] md:min-h-[8rem] lg:min-h-[10rem] overflow-hidden px-2 md:px-0">
      {/* Mobile wrapper with centering transform */}
      <div className="w-full md:hidden flex justify-center">
        <AnimatePresence mode="wait">
          <motion.svg
            key={`${currentSvgIndex}-mobile`}
            variants={containerVariants}
            viewBox={viewBox}
            fill="none"
            xmlns="http://www.w3.org/2000/svg"
            className="h-16 w-auto max-w-full"
            style={{ display: "block" }}
            initial="hidden"
            animate="visible"
            exit="hidden"
          >
            <g transform={`translate(${centerOffset}, 0)`}>
              {currentPaths.map((path, index) => (
                <motion.path
                  key={`${currentSvgIndex}-mobile-${index}`}
                  d={path}
                  stroke="currentColor"
                  strokeWidth="15"
                  strokeLinecap="round"
                  className="text-primary"
                  variants={draw}
                  custom={index}
                  initial="hidden"
                  animate="visible"
                  exit="exit"
                />
              ))}
            </g>
          </motion.svg>
        </AnimatePresence>
      </div>
      {/* Desktop — centered to match mobile */}
      <div className="hidden md:flex w-full justify-center">
        <AnimatePresence mode="wait">
          <motion.svg
            key={`${currentSvgIndex}-desktop`}
            variants={containerVariants}
            viewBox={viewBox}
            fill="none"
            xmlns="http://www.w3.org/2000/svg"
            className="h-24 lg:h-32 w-auto max-w-full"
            style={{ display: "block" }}
            initial="hidden"
            animate="visible"
            exit="hidden"
          >
            <g transform={`translate(${centerOffset}, 0)`}>
              {currentPaths.map((path, index) => (
                <motion.path
                  key={`${currentSvgIndex}-desktop-${index}`}
                  d={path}
                  stroke="currentColor"
                  strokeWidth="15"
                  strokeLinecap="round"
                  className="text-primary"
                  variants={draw}
                  custom={index}
                  initial="hidden"
                  animate="visible"
                  exit="exit"
                />
              ))}
            </g>
          </motion.svg>
        </AnimatePresence>
      </div>
    </div>
  );
};

export default HandwritingMVP;
